import React, { createContext, useState, useContext, useEffect } from 'react';
import axios from 'axios';
import toast from 'react-hot-toast';
import { 
  auth, 
  db,
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  signOut,
  collection,
  doc,
  setDoc,
  getDoc,
  getDocs,
  addDoc,
  updateDoc,
  deleteDoc,
  query,
  where
} from '../firebase';

const FarmContext = createContext();
export const useFarm = () => useContext(FarmContext);

const API_URL = 'http://localhost:8000/api';

export const FarmProvider = ({ children }) => {
  const [farm, setFarm] = useState(null);
  const [crops, setCrops] = useState([]);
  const [loading, setLoading] = useState(false);
  const [user, setUser] = useState(null);

  // Monitor auth state
  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged(async (user) => {
      if (user) {
        setUser(user);
        // Load farm profile from Firestore
        const farmDoc = await getDoc(doc(db, 'farms', user.uid));
        if (farmDoc.exists()) {
          setFarm({ uid: user.uid, ...farmDoc.data() });
        }
        await loadCrops(user.uid);
      } else {
        setUser(null);
        setFarm(null);
        setCrops([]);
      }
    });
    return () => unsubscribe();
  }, []);

  const registerWithFirebase = async (email, password, farmData) => {
    setLoading(true);
    try {
      // Create user in Firebase Auth
      const userCredential = await createUserWithEmailAndPassword(auth, email, password);
      const user = userCredential.user;

      // Store farm profile in Firestore
      const farmProfile = {
        uid: user.uid,
        email: email,
        farm_name: farmData.farm_name,
        owner_name: farmData.owner_name,
        phone: farmData.phone,
        address: farmData.address,
        total_area: farmData.total_area,
        soil_type: farmData.soil_type,
        irrigation_type: farmData.irrigation_type,
        created_at: new Date().toISOString()
      };

      await setDoc(doc(db, 'farms', user.uid), farmProfile);

      // Also register with backend
      await axios.post(`${API_URL}/firebase-auth`, {
        id_token: await user.getIdToken(),
        email: email,
        farm_name: farmData.farm_name,
        owner_name: farmData.owner_name,
        phone: farmData.phone,
        address: farmData.address,
        total_area: farmData.total_area
      });

      toast.success('Farm registered successfully!');
      return { success: true };
    } catch (error) {
      console.error('Registration error:', error);
      toast.error(error.message || 'Registration failed');
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  const loginWithFirebase = async (email, password) => {
    setLoading(true);
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const user = userCredential.user;

      // Get farm profile from Firestore
      const farmDoc = await getDoc(doc(db, 'farms', user.uid));
      if (farmDoc.exists()) {
        setFarm({ uid: user.uid, ...farmDoc.data() });
      }

      // Authenticate with backend
      await axios.post(`${API_URL}/firebase-auth`, {
        id_token: await user.getIdToken(),
        email: email
      });

      toast.success('Login successful!');
      return { success: true };
    } catch (error) {
      console.error('Login error:', error);
      toast.error(error.message || 'Login failed');
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  const logout = async () => {
    try {
      await signOut(auth);
      setFarm(null);
      setCrops([]);
      toast.success('Logged out successfully');
    } catch (error) {
      toast.error('Logout failed');
    }
  };

  const loadCrops = async (farmId) => {
    if (!farmId) return;

    setLoading(true);
    try {
      // Get crops from Firestore
      const q = query(collection(db, 'crops'), where('farm_id', '==', farmId));
      const querySnapshot = await getDocs(q);
      const cropsList = [];
      querySnapshot.forEach((doc) => {
        cropsList.push({ id: doc.id, ...doc.data() });
      });

      // Enhance with calculations
      const enhancedCrops = cropsList.map(crop => {
        const plantingDate = new Date(crop.planting_date);
        const today = new Date();
        const daysPlanted = Math.floor((today - plantingDate) / (1000 * 60 * 60 * 24));
        const daysRemaining = Math.max(0, crop.expected_days_to_harvest - daysPlanted);
        const harvestPercentage = Math.min(100, Math.floor((daysPlanted / crop.expected_days_to_harvest) * 100));

        let status, statusText, statusColor;
        if (daysRemaining <= 0) {
          status = 'ready_to_harvest';
          statusText = 'Ready to Harvest!';
          statusColor = '#10b981';
        } else if (daysRemaining <= 7) {
          status = 'harvest_soon';
          statusText = `Harvest in ${daysRemaining} days`;
          statusColor = '#f59e0b';
        } else if (daysRemaining <= 14) {
          status = 'maturing';
          statusText = `${daysRemaining} days remaining`;
          statusColor = '#3b82f6';
        } else {
          status = 'growing';
          statusText = `${daysRemaining} days to harvest`;
          statusColor = '#8b5cf6';
        }

        return {
          ...crop,
          days_planted: daysPlanted,
          days_remaining: daysRemaining,
          harvest_percentage: harvestPercentage,
          status,
          status_text: statusText,
          status_color: statusColor,
          health_status: daysPlanted % 3 !== 0 ? 'healthy' : 'check',
          health_text: daysPlanted % 3 !== 0 ? 'Healthy' : 'Needs Inspection'
        };
      });

      setCrops(enhancedCrops);
    } catch (error) {
      console.error('Error loading crops:', error);
      toast.error('Failed to load crops');
    } finally {
      setLoading(false);
    }
  };

  const addCrop = async (cropData) => {
    setLoading(true);
    try {
      const newCrop = {
        ...cropData,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString()
      };

      const docRef = await addDoc(collection(db, 'crops'), newCrop);
      toast.success('Crop added successfully!');
      await loadCrops(cropData.farm_id);
      return { success: true, crop_id: docRef.id };
    } catch (error) {
      console.error('Error adding crop:', error);
      toast.error('Failed to add crop');
      return { success: false };
    } finally {
      setLoading(false);
    }
  };

  const updateCrop = async (cropId, updates) => {
    setLoading(true);
    try {
      await updateDoc(doc(db, 'crops', cropId), {
        ...updates,
        updated_at: new Date().toISOString()
      });
      toast.success('Crop updated successfully');
      await loadCrops(farm?.uid);
      return true;
    } catch (error) {
      console.error('Error updating crop:', error);
      toast.error('Failed to update crop');
      return false;
    } finally {
      setLoading(false);
    }
  };

  const deleteCrop = async (cropId) => {
    setLoading(true);
    try {
      await deleteDoc(doc(db, 'crops', cropId));
      toast.success('Crop deleted successfully');
      await loadCrops(farm?.uid);
      return true;
    } catch (error) {
      console.error('Error deleting crop:', error);
      toast.error('Failed to delete crop');
      return false;
    } finally {
      setLoading(false);
    }
  };

  const updateFarmProfile = async (uid, updates) => {
    setLoading(true);
    try {
      await updateDoc(doc(db, 'farms', uid), updates);
      setFarm(prev => ({ ...prev, ...updates }));
      toast.success('Profile updated successfully');
      return true;
    } catch (error) {
      console.error('Error updating farm:', error);
      toast.error('Failed to update profile');
      return false;
    } finally {
      setLoading(false);
    }
  };

  return (
    <FarmContext.Provider value={{
      user,
      farm,
      crops,
      loading,
      registerWithFirebase,
      loginWithFirebase,
      logout,
      loadCrops,
      addCrop,
      updateCrop,
      deleteCrop,
      updateFarmProfile
    }}>
      {children}
    </FarmContext.Provider>
  );
};
